    providerOptions, headers, abortSignal
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<...> {
    const warnings: Array<SharedV3Warning> = [];

    // Add warnings for unsupported features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'This model does not support aspect ratio. Use `size` instead.'
      });
    }

    // Call API
    const { value: response, responseHeaders } = await postJsonToApi({...});

    // Return result
    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      usage: response.usage ? {...} : undefined,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        openai: {  // Keyed by provider name
          images: response.data.map((item, index) => ({
            revisedPrompt: item.revised_prompt,
            created: response.created,
            ...
          })),
        },
      },
    };
  }
}
```

### 5. Provider Factory Pattern

**OpenAI Provider Factory** (`/packages/openai/src/openai-provider.ts`):

```typescript
export function createOpenAI(options: OpenAIProviderSettings = {}): OpenAIProvider {
  const baseURL = options.baseURL ?? 'https://api.openai.com/v1';
  const providerName = options.name ?? 'openai';

  const getHeaders = () => ({
    Authorization: `Bearer ${loadApiKey({...})}`,
    ...options.headers,
  });

  // Create model factory function
  const createImageModel = (modelId: OpenAIImageModelId) =>
    new OpenAIImageModel(modelId, {
      provider: `${providerName}.image`,  // e.g., "openai.image"
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  // Build provider object with all supported model types
  const provider = function (modelId: OpenAIResponsesModelId) {
    return createLanguageModel(modelId);
  };

  provider.specificationVersion = 'v3' as const;
  provider.languageModel = createLanguageModel;
  provider.chat = createChatModel;
  provider.embedding = createEmbeddingModel;
  provider.embeddingModel = createEmbeddingModel;

  // Add image support
  provider.image = createImageModel;
  provider.imageModel = createImageModel;

  provider.transcription = createTranscriptionModel;
  provider.speech = createSpeechModel;

  return provider as OpenAIProvider;
}

export const openai = createOpenAI();
```

### 6. Image-Only Provider Example (FAL)

**FAL Provider Interface** (`/packages/fal/src/fal-provider.ts`):

```typescript
export interface FalProvider extends ProviderV3 {
  image(modelId: FalImageModelId): ImageModelV3;
  imageModel(modelId: FalImageModelId): ImageModelV3;
  transcription(modelId: FalTranscriptionModelId): TranscriptionModelV3;
  video(modelId: FalVideoModelId): Experimental_VideoModelV3;
  speech(modelId: FalSpeechModelId): SpeechModelV3;
  // Throws NoSuchModelError for unsupported types
  textEmbeddingModel(modelId: string): never;
}

export function createFal(options: FalProviderSettings = {}): FalProvider {
  const createImageModel = (modelId: FalImageModelId) =>
    new FalImageModel(modelId, {
      provider: 'fal.image',  // Note: "fal.image" not just "fal"
      baseURL: options.baseURL ?? 'https://fal.run',
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3' as const,
    imageModel: createImageModel,
    image: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'languageModel',
      });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({...});
    },
    // ... other models
  };
}

export const fal = createFal();
```

### 7. AI SDK Integration (`/packages/ai/src/generate-image/`)

**generateImage Function** (`/packages/ai/src/generate-image/generate-image.ts`):

```typescript
export async function generateImage({
  model: modelArg,           // ImageModel type
  prompt: promptArg,         // string | {images, text?, mask}
  n = 1,                     // Number of images
  maxImagesPerCall,          // Override model's limit
  size,                      // "1024x1024" format
  aspectRatio,               // "16:9" format
  seed,
  providerOptions,           // {[provider]: {...}}
  maxRetries = 2,
  abortSignal,
  headers,
}: {...}): Promise<GenerateImageResult> {
  const model = resolveImageModel(modelArg);  // String -> actual model instance

  // Handle parallelization based on maxImagesPerCall
  const maxImagesPerCallWithDefault = 
    maxImagesPerCall ?? (await invokeModelMaxImagesPerCall(model)) ?? 1;

  const callCount = Math.ceil(n / maxImagesPerCallWithDefault);

  // Make parallel API calls if needed
  const results = await Promise.all(
    callImageCounts.map(callImageCount =>
      retry(() => model.doGenerate({
        prompt,
        files,
        mask,
        n: callImageCount,
        abortSignal,
        headers,
        size,
        aspectRatio,
        seed,
        providerOptions,
      }))
    )
  );

  return new DefaultGenerateImageResult({
    images,
    warnings,
    responses,
    providerMetadata,
    usage: totalUsage,
  });
}
```

**Result Type:**
```typescript
interface GenerateImageResult {
  images: Array<GeneratedFile>;
  image: GeneratedFile;  // First image
  warnings: Array<Warning>;
  responses: Array<ImageModelResponseMetadata>;
  providerMetadata: ImageModelV3ProviderMetadata;
  usage: ImageModelUsage;
}
```

### 8. Key Patterns & Requirements

**For Creating an Image-Only Provider:**

1. **Create provider package** (e.g., `@ai-sdk/my-provider`)
   - Dependencies: `@ai-sdk/provider`, `@ai-sdk/provider-utils`
   - Export: `createMyProvider()` factory and default instance

2. **Implement ImageModelV3 class:**
   - Set `specificationVersion = 'v3'`
   - Implement `doGenerate()` method
   - Set `provider` getter (e.g., "my-provider.image")
   - Set `maxImagesPerCall` (number or function)

3. **Create Provider interface extending ProviderV3:**
   - Only implement `imageModel(modelId): ImageModelV3`
   - Throw `NoSuchModelError` for `languageModel`, `embeddingModel`, etc.

4. **Return provider object from factory:**
   ```typescript
   {
     specificationVersion: 'v3',
     imageModel: createImageModel,
     image: createImageModel,
     languageModel: (id) => throw NoSuchModelError(...),
     embeddingModel: (id) => throw NoSuchModelError(...),
     // ... other required methods that throw
   }
   ```

5. **Export from main index.ts:**
   ```typescript
   export { createMyProvider, myProvider } from './my-provider';
   export type { MyProviderSettings, MyProvider } from './my-provider';
   ```

**Key Configuration Pattern:**
```typescript
interface ImageModelConfig {
  provider: string;           // e.g., "myProvider.image"
  baseURL?: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date; // For testing
  };
}
```

**Provider Metadata:**
- Must be keyed by provider name: `{ "myProvider": { images: [...] } }`
- Each entry must have `images` array with per-image metadata

### 9. TypeScript Configuration

**Pattern for provider packages:**
- Extends `@vercel/ai-tsconfig/ts-library.json`
- References depend on: `../provider`, `../provider-utils`
- Build with tsup, outputs both ESM and CJS

### 10. Related File Paths

**Provider Package Structure:**
- `/packages/provider/src/image-model/v3/` - ImageModelV3 types and interfaces
- `/packages/provider/src/image-model/v2/` - Legacy ImageModelV2 (for backwards compatibility)
- `/packages/ai/src/generate-image/` - generateImage SDK function
- `/packages/ai/src/types/image-model.ts` - Type unions (V2 | V3)
- `/packages/ai/src/model/resolve-model.ts` - String->Model instance resolution

This structure provides backward compatibility (V2 still supported) while pushing new providers toward V3, which has more features (file handling, aspect ratios, masks).

